// ==============================================================
// Celetista - Buscar empregado no RM (autocomplete CLT)
// Entrada:  ?nome=<string> (minimo 3 caracteres)
// Saida:    { resultados: [{nome, chapa, cpf, funcao, admissao, secao, codcoligada}, ...] }
// SQL:      consulta nomeada no RM (cadastrada com nome proprio CLT).
//           Filtra por PFU.CODCATEGORIAESOCIAL <> '111' (exclui intermitentes)
//           + PFU.CODSITUACAO <> 'D' (exclui demitidos)
//           + PFU.NOME LIKE :NOME.
// SQL esperada no RM:
// SELECT PFU.NOME AS 'Nome', PFU.CHAPA AS 'Chapa', PPE.CPF AS 'CPF',
//        PFC.NOME AS 'Fun??o', PFU.DATAADMISSAO AS 'Admiss?o', PSE.DESCRICAO AS 'Se??o'
// FROM PFUNC PFU (NOLOCK)
// INNER JOIN PFCOMPL PCC (NOLOCK) ON PCC.CODCOLIGADA = PFU.CODCOLIGADA AND PCC.CHAPA = PFU.CHAPA
// INNER JOIN PSECAO PSE (NOLOCK) ON PSE.CODCOLIGADA = PFU.CODCOLIGADA AND PSE.CODIGO = PFU.CODSECAO
// INNER JOIN PPESSOA PPE (NOLOCK) ON PPE.CODIGO = PFU.CODPESSOA
// INNER JOIN PFUNCAO PFC (NOLOCK) ON PFC.CODCOLIGADA = PFU.CODCOLIGADA AND PFC.CODIGO = PFU.CODFUNCAO
// WHERE PFU.CODCOLIGADA = :$CODCOLIGADA
//   AND PFU.CODSITUACAO <> 'D'
//   AND PFU.CODCATEGORIAESOCIAL <> '111'
//   AND PFU.NOME LIKE :NOME.
// ==============================================================

const nomeRaw = ($json.query?.nome || '').toString().trim();

if (nomeRaw.length < 3) {
  return [{
    json: {
      _statusCode: 200,
      _skip: true,
      resultados: []
    }
  }];
}

// Trocar PFP CLT pelo nome real da SQL cadastrada no RM TOTVS, se mudar.
const SQL_NAME = encodeURIComponent('PFP CLT');
const nomeParaRM = encodeURIComponent('%' + nomeRaw + '%');
const urlRM = 'https://contatoservicos165112.rm.cloudtotvs.com.br:8051/api/framework/v1/consultaSQLServer/RealizaConsulta/' + SQL_NAME + '/3/P/?parameters=$CODCOLIGADA%3D3%3BNOME%3D' + nomeParaRM;

return [{
  json: {
    nomeRaw,
    urlRM
  }
}];

// ==============================================================
// Celetista - Normaliza resposta do RM em shape camelCase
// Mapeamento dos campos da SQL CLT:
//   'Nome'            -> nome
//   'Chapa'           -> chapa
//   'CPF'             -> cpf
//   'Funcao'          -> funcao
//   'Admissao'        -> admissao (YYYY-MM-DD)
//   'Secao'           -> secao
//
// Nota: o HTTP Request do n8n quebra a resposta JSON-array do RM
//       em N items (1 por linha). Por isso iteramos $input.all().
// ==============================================================

function normalizaAdmissao(v) {
  if (!v) return '';
  const s = String(v).trim();
  const m = s.match(/^(\d{4}-\d{2}-\d{2})/);
  if (m) return m[1];
  const m2 = s.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
  if (m2) return m2[3] + '-' + m2[2] + '-' + m2[1];
  return s;
}

function extrairLinhas(item) {
  const j = item?.json;
  if (!j) return [];
  if (Array.isArray(j)) return j;
  if (Array.isArray(j.body)) return j.body;
  if (Array.isArray(j.value)) return j.value;
  if (Array.isArray(j.data)) return j.data;
  if (j['Nome'] || j['Chapa'] || j.nome) return [j];
  return [];
}

const todos = $input.all();
const linhas = todos.flatMap(extrairLinhas);

const resultados = linhas
  .map((r) => ({
    nome: String(r['Nome'] || r.nome || '').trim(),
    chapa: String(r['Chapa'] || r.chapa || '').trim(),
    cpf: String(r['CPF'] || r.cpf || '').trim(),
    funcao: String(r['Função'] || r['Funcao'] || r.funcao || '').trim(),
    admissao: normalizaAdmissao(r['Admissão'] || r['Admissao'] || r.admissao),
    secao: String(r['Seção'] || r['Secao'] || r.secao || '').trim(),
    codcoligada: 3
  }))
  .filter((e) => e.nome.length > 0);

const vistos = new Set();
const dedup = [];
for (const r of resultados) {
  const key = r.chapa || r.nome;
  if (vistos.has(key)) continue;
  vistos.add(key);
  dedup.push(r);
}

return [{
  json: {
    _statusCode: 200,
    resultados: dedup
  }
}];
